import React, { useEffect, useState } from "react";

function App() {
  // State management
  const [incidents, setIncidents] = useState([]);
  const [component, setComponent] = useState("");
  const [message, setMessage] = useState("");
  const [selectedIncident, setSelectedIncident] = useState(null);
  const [showRCAForm, setShowRCAForm] = useState(null);
  const [rcaData, setRcaData] = useState({ root: "", fix: "" });

  // Fetch incidents from backend and sort by severity
  const fetchIncidents = async () => {
    const res = await fetch("http://127.0.0.1:8000/incidents");
    const data = await res.json();

    const priority = { P0: 1, P1: 2, P2: 3 };

    const sorted = data.sort(
      (a, b) => priority[a.severity] - priority[b.severity]
    );

    setIncidents(sorted);
  };

  // Polling for real-time updates
  useEffect(() => {
    fetchIncidents();
    const interval = setInterval(fetchIncidents, 3000);
    return () => clearInterval(interval);
  }, []);

  // Send new signal
  const sendSignal = async () => {
    if (!component || !message) {
      alert("⚠️ Please enter Component ID and Message");
      return;
    }

    const res = await fetch(
      `http://127.0.0.1:8000/ingest?component_id=${component}&message=${message}`,
      { method: "POST" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert("✅ Incident Created Successfully");
      setComponent("");
      setMessage("");
      fetchIncidents();
    }
  };

  // Submit RCA
  const submitRCA = async (id) => {
    if (!rcaData.root || !rcaData.fix) {
      alert("⚠️ Please fill all RCA fields");
      return;
    }

    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/rca?root_cause=${rcaData.root}&fix=${rcaData.fix}`,
      { method: "POST" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert("✅ RCA Added Successfully");
      setShowRCAForm(null);
      setRcaData({ root: "", fix: "" });
    }

    fetchIncidents();
  };

  // Close incident
  const closeIncident = async (id) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=CLOSED`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      let message = data.detail;

      if (message.includes("Invalid transition")) {
        message = "⚠️ Move incident to RESOLVED before closing";
      }

      if (message.includes("RCA required")) {
        message = "⚠️ Add RCA before closing";
      }

      alert(message);
    } else {
      alert("✅ Incident Closed Successfully");
    }

    fetchIncidents();
  };

  // Update incident status
  const updateStatus = async (id, status) => {
    const res = await fetch(
      `http://127.0.0.1:8000/incident/${id}/status?status=${status}`,
      { method: "PUT" }
    );

    const data = await res.json();

    if (!res.ok) {
      alert("❌ " + data.detail);
    } else {
      alert(`✅ Moved to ${status}`);
    }

    fetchIncidents();
  };

  // Show only active incidents
  const activeIncidents = incidents.filter(
    (inc) => inc.status !== "CLOSED"
  );

  return (
    <div style={{ padding: "20px" }}>
      <h1>🚨 Incident Dashboard</h1>

      {/* Input section */}
      <div style={{ marginBottom: "15px" }}>
        <input
          placeholder="Component ID"
          value={component}
          onChange={(e) => setComponent(e.target.value)}
        />
        <input
          placeholder="Message"
          value={message}
          onChange={(e) => setMessage(e.target.value)}
        />
        <button onClick={sendSignal}>Send Signal</button>
      </div>

      <hr />

      <h2>Active Incidents ({activeIncidents.length})</h2>

      {/* Incident cards */}
      {activeIncidents.map((inc) => (
        <div
          key={inc.id}
          onClick={() =>
            setSelectedIncident(
              selectedIncident === inc.id ? null : inc.id
            )
          }
          style={{
            border: "1px solid #ccc",
            borderRadius: "8px",
            margin: "10px",
            padding: "15px",
            cursor: "pointer",
            backgroundColor:
              inc.severity === "P0"
                ? "#ffe5e5"
                : inc.severity === "P1"
                ? "#fff8e1"
                : "#f4f4f4"
          }}
        >
          <h3>Incident #{inc.id}</h3>

          <p><b>Component:</b> {inc.component_id}</p>

          <p>
            <b>Severity:</b>{" "}
            <span
              style={{
                padding: "4px 8px",
                borderRadius: "5px",
                color: "white",
                backgroundColor:
                  inc.severity === "P0"
                    ? "red"
                    : inc.severity === "P1"
                    ? "orange"
                    : "gray"
              }}
            >
              {inc.severity}
            </span>
          </p>

          <p><b>Status:</b> {inc.status}</p>
          <p><b>Signals:</b> {inc.signals.length}</p>

          {/* RCA details */}
          {inc.rca && (
            <>
              <p><b>Root Cause:</b> {inc.rca.root_cause}</p>
              <p><b>Fix:</b> {inc.rca.fix}</p>
              <p><b>MTTR:</b> {Math.round(inc.rca.mttr_seconds)} sec</p>
            </>
          )}

          {/* Expandable signal view */}
          {selectedIncident === inc.id && (
            <div style={{ marginTop: "10px" }}>
              <h4>Signal Details</h4>
              {inc.signals.map((sig, index) => (
                <div key={index} style={{ fontSize: "13px" }}>
                  <p><b>Message:</b> {sig.message}</p>
                  <p><b>Time:</b> {new Date(sig.timestamp).toLocaleString()}</p>
                  <hr />
                </div>
              ))}
            </div>
          )}

          {/* Action buttons */}
          <div style={{ marginTop: "10px" }}>
            <button
              onClick={(e) => {
                e.stopPropagation();
                updateStatus(inc.id, "INVESTIGATING");
              }}
              disabled={inc.status !== "OPEN"}
            >
              Investigate
            </button>

            <button
              onClick={(e) => {
                e.stopPropagation();
                updateStatus(inc.id, "RESOLVED");
              }}
              disabled={inc.status !== "INVESTIGATING"}
            >
              Resolve
            </button>

            <button
              onClick={(e) => {
                e.stopPropagation();
                setShowRCAForm(inc.id);
              }}
              disabled={inc.status !== "RESOLVED" || inc.rca}
            >
              Add RCA
            </button>

            <button
              onClick={(e) => {
                e.stopPropagation();
                closeIncident(inc.id);
              }}
              disabled={inc.status !== "RESOLVED" || !inc.rca}
            >
              Close
            </button>
          </div>

          {/* RCA Form */}
          {showRCAForm === inc.id && (
            <div
              style={{
                marginTop: "10px",
                padding: "10px",
                border: "1px solid #ddd",
                borderRadius: "6px",
                backgroundColor: "#fff"
              }}
              onClick={(e) => e.stopPropagation()}
            >
              <h4>RCA Form</h4>

              <input
                placeholder="Root Cause"
                value={rcaData.root}
                onChange={(e) =>
                  setRcaData({ ...rcaData, root: e.target.value })
                }
                style={{ width: "100%", marginBottom: "8px" }}
              />

              <textarea
                placeholder="Fix Applied"
                value={rcaData.fix}
                onChange={(e) =>
                  setRcaData({ ...rcaData, fix: e.target.value })
                }
                style={{ width: "100%", marginBottom: "8px" }}
              />

              <button onClick={() => submitRCA(inc.id)}>
                Submit RCA
              </button>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

export default App;
